final:
module gray_code_counter_2bit (
    input clk,
    input rst,
    output reg [1:0] gray
);

reg [1:0] err_binary;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        err_binary <= 2'b00;
    end else begin
        err_binary <= err_binary + 1;
    end
end

always @(err_binary) begin
    gray = err_binary ^ (err_binary >> 1);
end

endmodule
